(window.webpackJsonp=window.webpackJsonp||[]).push([[208],{835:function(n,t){n.exports="\x3c!-- \ntitle: 11-Linux常用指令\nsort: \n--\x3e \n# linux常用指令\n\n## 建立链接\n\n- 软链接（快捷方式）\n  - ln -s\n- 硬链接（多个名字）\n  - ln\n\n##  文件搜索\n\n+ 在文本内部搜索（grep）\n\n  > grep “内容” 文件路径\n  >\n  > -n\t  查看行数\n  >\n  > -i\t\t忽略大小写\n  >\n  > -v\t\t取反\n\n+ 在计算机内搜索文件（find）\n\n  > find 目标目录 选项 条件 \n  >\n  > -name\t按名称\n  >\n  > -size\t\t按大小\n  >\n  > > +32M\t大于32M\n  > >\n  > > -15M\t小于15M\n\n## 归档和压缩\n\n`gzip`\n\n> -d: 解压缩\n\n`tar`\n\n> tar 选项 源文件 输出文件\n\n- 归档和解档\n  \n  > -cvf\n  >\n  > -xvf\n  \n- 压缩和解压\n  \n  > -zcvf\n  >\n  > -zxvf\n  >\n  \n- zip压缩及解压\n  > zip -r 文件名 源文件名\n  >\n  > unzip 文件名\n## 文件权限\n\n```BASH\nchmod [-cfvR] [--help] [--version] [ugoa...][[+-=][rwxX]\n```\n\n- 权限修改（chmod）\n\n  > -Rv：显示详细信息与设置\n  >\n  > 用户：u g o a\n  >\n  > 权限设置：+ - =\n  >\n  > 用法：chmod a=rwx\n  >\n  > rwx：421\n  >\n  > chmod 777\t最高权限\n  >\n  > chmod -R 755 目录\t递归分配权限\n\n## 用户管理\n\n- sudo -s\t切换用户\n\n- passwd    修改密码\n\n- who         切换用户\n\n- 关机\n\n  > shutdown -c\t取消关机\n  >\n  > shutdown now\t现在关机\n  >\n  > shudown -r now\t重启\n  >\n  > shutdown +20\t20分钟后关机\n\n## 远程操作\n\n+ ssh\t远程连接\n\n+ scp    远程拷贝\n\n  > scp 源文件目录 目标文件目录\n\n"}}]);